<template><ContentWrap><el-form :inline="true" class="mb-10px"><el-form-item :label="t('crm.marketing.name')"><el-input v-model="query.name" clearable @keyup.enter="reload" /></el-form-item><el-button type="primary" @click="reload">{{ t('common.query') }}</el-button><el-button @click="openCreate">{{ t('common.create') }}</el-button></el-form><el-table v-loading="loading" :data="list"><el-table-column prop="name" :label="t('crm.marketing.name')" /><el-table-column prop="website" :label="t('crm.marketing.website')" /><el-table-column prop="ownerUserName" :label="t('crm.marketing.owner')" /><el-table-column prop="strengths" :label="t('crm.marketing.strengths')" /><el-table-column prop="weaknesses" :label="t('crm.marketing.weaknesses')" /><el-table-column fixed="right" :label="t('common.action')"><template #default="scope"><el-button link type="danger" @click="remove(scope.row.id)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><Pagination v-model:page="query.pageNo" v-model:limit="query.pageSize" :total="total" @pagination="reload" /><el-dialog v-model="dialogVisible" :title="t('crm.marketing.createCompetitor')"><el-form :model="form" label-width="100px"><el-form-item :label="t('crm.marketing.name')"><el-input v-model="form.name" /></el-form-item><el-form-item :label="t('crm.marketing.website')"><el-input v-model="form.website" /></el-form-item><el-form-item :label="t('crm.marketing.ownerUserId')"><el-input-number v-model="form.ownerUserId" :min="1" /></el-form-item><el-form-item :label="t('crm.marketing.strengths')"><el-input v-model="form.strengths" type="textarea" /></el-form-item><el-form-item :label="t('crm.marketing.weaknesses')"><el-input v-model="form.weaknesses" type="textarea" /></el-form-item></el-form><template #footer><el-button @click="dialogVisible = false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.ok') }}</el-button></template></el-dialog></ContentWrap></template>
<script setup lang="ts">import { ref, reactive } from 'vue'; import { useI18n } from '@/hooks/web/useI18n'; import * as Api from '@/api/crm/marketing'; import { ElMessageBox } from 'element-plus'; const { t } = useI18n(); const loading=ref(false); const list=ref<any[]>([]); const total=ref(0); const dialogVisible=ref(false); const query=reactive({pageNo:1,pageSize:10,name:''}); const form=reactive<any>({name:'',website:'',ownerUserId:1,strengths:'',weaknesses:''}); const reload=async()=>{loading.value=true;try{const r=await Api.getCompetitorPage(query);list.value=r.list||[];total.value=r.total||0}finally{loading.value=false}}; const openCreate=()=>{Object.assign(form,{name:'',website:'',ownerUserId:1,strengths:'',weaknesses:''});dialogVisible.value=true}; const save=async()=>{await Api.saveCompetitor(form);dialogVisible.value=false;reload()}; const remove=async(id:number)=>{await ElMessageBox.confirm(t('common.delMessage'));await Api.deleteCompetitor(id);reload()}; reload()</script>
